func TestRateLimiter_GetLimiter(t *testing.T) {
	rl := NewRateLimiter(rate.Every(time.Second), 5, time.Minute)

	// Test getting a limiter for a new IP
	limiter1 := rl.GetLimiter("192.168.1.1")
	if limiter1 == nil {
