// Helper function to check if string contains substring
func contains(s, substr string) bool {
	return len(s) >= len(substr) && s[:len(substr)] == substr ||
		(len(s) > len(substr) && containsHelper(s[1:], substr))
}

func containsHelper(s, substr string) bool {
	if len(s) < len(substr) {
		return false
	}
	if s[:len(substr)] == substr {
		return true
	}
	return containsHelper(s[1:], substr)
}

package security

import (
	"net"
	"net/http"
	"strings"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

// RateLimiter manages rate limiting for different clients/IPs
type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
	cleanup  time.Duration
}

// NewRateLimiter creates a new rate limiter
func NewRateLimiter(r rate.Limit, b int, cleanup time.Duration) *RateLimiter {
	rl := &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
		cleanup:  cleanup,
	}

	// Start cleanup goroutine
	go rl.cleanupRoutine()

	return rl
}

// GetLimiter returns the rate limiter for a given key (IP address)
func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}

	return limiter
}

// cleanupRoutine periodically removes unused limiters
func (rl *RateLimiter) cleanupRoutine() {
	ticker := time.NewTicker(rl.cleanup)
	defer ticker.Stop()

	for range ticker.C {
		rl.mu.Lock()
		for key, limiter := range rl.limiters {
			// Remove limiters that haven't been used recently
			if limiter.TokensAt(time.Now()) == float64(rl.burst) {
				delete(rl.limiters, key)
			}
		}
		rl.mu.Unlock()
	}
}

// RateLimitConfig holds configuration for different rate limits
type RateLimitConfig struct {
	LoginRate         rate.Limit // requests per second for login attempts
	LoginBurst        int        // max burst for login attempts
	GeneralRate       rate.Limit // requests per second for general API
	GeneralBurst      int        // max burst for general API
	CleanupInterval   time.Duration
	TrustProxyHeaders bool
}

// DefaultRateLimitConfig returns sensible default rate limits
func DefaultRateLimitConfig() RateLimitConfig {
	return RateLimitConfig{
		LoginRate:       rate.Every(10 * time.Second), // 1 login attempt per 10 seconds
		LoginBurst:      3,                            // Allow burst of 3 attempts
		GeneralRate:     rate.Every(time.Second),      // 1 request per second
		GeneralBurst:    10,                           // Allow burst of 10 requests
		CleanupInterval: 5 * time.Minute,              // Cleanup every 5 minutes
	}
}

// RateLimitMiddleware creates a rate limiting middleware
func RateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return RateLimitMiddlewareWithProxyTrust(limiter, false)
}

// RateLimitMiddlewareWithProxyTrust creates rate limiting middleware with explicit proxy-header posture.
func RateLimitMiddlewareWithProxyTrust(limiter *RateLimiter, trustProxy bool) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIPWithProxyTrust(r, trustProxy)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				WriteRateLimited(w, RuntimeReasonRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// LoginRateLimitMiddleware creates a stricter rate limit for login endpoints
func LoginRateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return LoginRateLimitMiddlewareWithProxyTrust(limiter, false)
}

// LoginRateLimitMiddlewareWithProxyTrust creates login rate limiting middleware with explicit proxy-header posture.
func LoginRateLimitMiddlewareWithProxyTrust(limiter *RateLimiter, trustProxy bool) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIPWithProxyTrust(r, trustProxy)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				WriteRateLimited(w, RuntimeReasonLoginRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// getClientIP extracts the client IP address from the request.
// Forwarded headers are only trusted when the deployment explicitly opts in.
func getClientIP(r *http.Request) string {
	return getClientIPWithProxyTrust(r, false)
}

func getClientIPWithProxyTrust(r *http.Request, trustProxy bool) string {
	if r == nil {
		return ""
	}

	if trustProxy {
		if forwarded := firstForwardedFor(r.Header.Get("X-Forwarded-For")); forwarded != "" {
			return forwarded
		}

		if realIP := headerIP(r.Header.Get("X-Real-IP")); realIP != "" {
			return realIP
		}
	}

	return remoteAddressHost(r.RemoteAddr)
}

func firstForwardedFor(value string) string {
	if strings.TrimSpace(value) == "" {
		return ""
	}
	parts := strings.Split(value, ",")
	return headerIP(parts[0])
}

func headerIP(value string) string {
	value = strings.TrimSpace(value)
	if value == "" || net.ParseIP(value) == nil {
		return ""
	}
	return value
}

func remoteAddressHost(remoteAddr string) string {
	remoteAddr = strings.TrimSpace(remoteAddr)
	if remoteAddr == "" {
		return ""
	}
	host, _, err := net.SplitHostPort(remoteAddr)
	if err == nil {
		return host
	}
	return remoteAddr
}

// RateLimitManager manages multiple rate limiters for different endpoints
type RateLimitManager struct {
	loginLimiter      *RateLimiter
	generalLimiter    *RateLimiter
	trustProxyHeaders bool
}

// NewRateLimitManager creates a new rate limit manager with default configuration
func NewRateLimitManager() *RateLimitManager {
	config := DefaultRateLimitConfig()

	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
		trustProxyHeaders: config.TrustProxyHeaders,
	}
}

// NewCustomRateLimitManager creates a rate limit manager with custom configuration
func NewCustomRateLimitManager(config RateLimitConfig) *RateLimitManager {
	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
		trustProxyHeaders: config.TrustProxyHeaders,
	}
}

// GetLoginMiddleware returns the login rate limiting middleware
func (rlm *RateLimitManager) GetLoginMiddleware() func(http.Handler) http.Handler {
	return LoginRateLimitMiddlewareWithProxyTrust(rlm.loginLimiter, rlm.trustProxyHeaders)
}

// GetGeneralMiddleware returns the general rate limiting middleware
func (rlm *RateLimitManager) GetGeneralMiddleware() func(http.Handler) http.Handler {
	return RateLimitMiddlewareWithProxyTrust(rlm.generalLimiter, rlm.trustProxyHeaders)
}

package runtime

import (
	"fmt"
	"os"
	"strconv"
	"strings"

	"socialpredict/security"
)

// CORSConfig describes the request-boundary CORS posture owned by runtime bootstrap.
type CORSConfig struct {
	Enabled          bool
	AllowedOrigins   []string
	AllowedMethods   []string
	AllowedHeaders   []string
	ExposedHeaders   []string
	AllowCredentials bool
	MaxAge           int
}

// SecurityConfig is the runtime-owned security posture for the process.
type SecurityConfig struct {
	JWTSigningKey     []byte
	TrustProxyHeaders bool
	CORS              CORSConfig
	Headers           security.SecurityHeaders
}

// LoadSecurityConfigFromEnv validates and freezes deployment-sensitive security settings.
func LoadSecurityConfigFromEnv() (SecurityConfig, error) {
	signingKey := []byte(strings.TrimSpace(os.Getenv("JWT_SIGNING_KEY")))
	if len(signingKey) == 0 {
		return SecurityConfig{}, fmt.Errorf("security config: JWT_SIGNING_KEY is required")
	}

	headers := security.DefaultSecurityHeaders()
	headers.StrictTransportSecurity = strictTransportSecurityHeader()

	return SecurityConfig{
		JWTSigningKey:     signingKey,
		TrustProxyHeaders: getRuntimeBoolEnv("TRUST_PROXY_HEADERS", false),
		CORS: CORSConfig{
			Enabled:          getRuntimeBoolEnv("CORS_ENABLED", true),
			AllowedOrigins:   getRuntimeListEnv("CORS_ALLOW_ORIGINS", "*"),
			AllowedMethods:   getRuntimeListEnv("CORS_ALLOW_METHODS", "GET,POST,PUT,PATCH,DELETE,OPTIONS"),
			AllowedHeaders:   getRuntimeListEnv("CORS_ALLOW_HEADERS", "Content-Type,Authorization"),
			ExposedHeaders:   getRuntimeListEnv("CORS_EXPOSE_HEADERS", ""),
			AllowCredentials: getRuntimeBoolEnv("CORS_ALLOW_CREDENTIALS", false),
			MaxAge:           getRuntimeIntEnv("CORS_MAX_AGE", 600),
		},
		Headers: headers,
	}, nil
}

func strictTransportSecurityHeader() string {
	if !getRuntimeBoolEnv("SECURITY_HSTS_ENABLED", false) {
		return ""
	}

	maxAge := getRuntimeIntEnv("SECURITY_HSTS_MAX_AGE", 31536000)
	parts := []string{fmt.Sprintf("max-age=%d", maxAge)}
	if getRuntimeBoolEnv("SECURITY_HSTS_INCLUDE_SUBDOMAINS", false) {
		parts = append(parts, "includeSubDomains")
	}
	if getRuntimeBoolEnv("SECURITY_HSTS_PRELOAD", false) {
		parts = append(parts, "preload")
	}
	return strings.Join(parts, "; ")
}

func getRuntimeListEnv(key, def string) []string {
	val := strings.TrimSpace(os.Getenv(key))
	if val == "" {
		val = def
	}
	if val == "" {
		return nil
	}

	parts := strings.Split(val, ",")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		part = strings.TrimSpace(part)
		if part != "" {
			out = append(out, part)
		}
	}
	return out
}

func getRuntimeBoolEnv(key string, def bool) bool {
	value := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
	if value == "" {
		return def
	}
	return value == "1" || value == "true" || value == "yes" || value == "on"
}

func getRuntimeIntEnv(key string, def int) int {
	value := strings.TrimSpace(os.Getenv(key))
	if value == "" {
		return def
	}
	parsed, err := strconv.Atoi(value)
	if err != nil {
		return def
	}
	return parsed
}

package security

import (
	"encoding/json"
	"net/http"
)

const (
	RuntimeReasonInternalError    = "INTERNAL_ERROR"
	RuntimeReasonLoginRateLimited = "LOGIN_RATE_LIMITED"
	RuntimeReasonMethodNotAllowed = "METHOD_NOT_ALLOWED"
	RuntimeReasonRateLimited      = "RATE_LIMITED"

	RuntimeErrorTypeInternal         = "runtime.internal"
	RuntimeErrorTypeMethodNotAllowed = "http.method_not_allowed"
	RuntimeErrorTypePanic            = "exception.panic"
	RuntimeErrorTypeRateLimited      = "http.rate_limited"
)

// RuntimeFailureResponse is the public runtime-boundary failure envelope.
type RuntimeFailureResponse struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

// RuntimeFailureErrorType returns the stable telemetry classification for
// runtime-owned HTTP failures. It is intentionally independent from public
// response reason strings.
func RuntimeFailureErrorType(statusCode int) (string, bool) {
	switch statusCode {
	case http.StatusMethodNotAllowed:
		return RuntimeErrorTypeMethodNotAllowed, true
	case http.StatusTooManyRequests:
		return RuntimeErrorTypeRateLimited, true
	case http.StatusInternalServerError:
		return RuntimeErrorTypeInternal, true
	default:
		return "", false
	}
}

// WriteMethodNotAllowed writes the shared runtime-owned 405 response.
func WriteMethodNotAllowed(w http.ResponseWriter) {
	writeRuntimeFailure(w, http.StatusMethodNotAllowed, RuntimeReasonMethodNotAllowed)
}

// WriteRateLimited writes the shared runtime-owned 429 response.
func WriteRateLimited(w http.ResponseWriter, reason string) {
	if reason == "" {
		reason = RuntimeReasonRateLimited
	}
	writeRuntimeFailure(w, http.StatusTooManyRequests, reason)
}

// WriteInternalServerError writes the shared sanitized runtime-owned 500 response.
func WriteInternalServerError(w http.ResponseWriter) {
	writeRuntimeFailure(w, http.StatusInternalServerError, RuntimeReasonInternalError)
}

func writeRuntimeFailure(w http.ResponseWriter, statusCode int, reason string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_ = json.NewEncoder(w).Encode(RuntimeFailureResponse{
		OK:     false,
		Reason: reason,
	})
}

